class TrieNode:
    def __init__(self):
        self.children = {}      # 子节点映射：字符 -> TrieNode
        self.is_end = False       # 标记是否为完整单词结尾

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        """插入一个单词到字典树"""
        node = self.root
        for ch in word:
            if ch not in node.children:
                node.children[ch] = TrieNode()
            node = node.children[ch]
        node.is_end = True          # 最后节点标记为单词结尾

    def search(self, word: str) -> bool:
        """精确搜索：判断单词是否存在于 Trie 中"""
        node = self.root
        for ch in word:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return node.is_end          # 必须到达结尾标记才为完整单词

    def starts_with(self, prefix: str) -> bool:
        """前缀搜索：判断是否有单词以该前缀开头"""
        node = self.root
        for ch in prefix:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return True                 # 能走完前缀即存在

    def collect_words(self, node: TrieNode, prefix: str) -> list:
        """收集以当前节点为根的所有单词（用于自动补全）"""
        result = []
        if node.is_end:
            result.append(prefix)
        for ch, child in node.children.items():
            result.extend(self.collect_words(child, prefix + ch))
        return result

    def autocomplete(self, prefix: str) -> list:
        """自动补全：返回所有以 prefix 开头的单词"""
        node = self.root
        for ch in prefix:
            if ch not in node.children:
                return []           # 前缀不存在，无匹配结果
            node = node.children[ch]
        return self.collect_words(node, prefix)


# 使用示例
trie = Trie()
for word in ["apple", "app", "application", "banana", "band"]:
    trie.insert(word)

print(trie.search("app"))           # True
print(trie.search("appl"))          # False
print(trie.autocomplete("app"))     # ['app', 'apple', 'application']
print(trie.autocomplete("ban"))     # ['banana', 'band']

# 使用 defaultdict 优化节点结构，支持更简洁的代码
from collections import defaultdict

class TrieNode:
    def __init__(self):
        self.children = defaultdict(TrieNode)  # 自动创建缺失节点
        self.is_end = False
        self.count = 0        # 记录经过该节点的单词数，用于前缀频次统计

class TrieWithCount:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for ch in word:
            node = node.children[ch]
            node.count += 1
        node.is_end = True

    def count_prefix(self, prefix: str) -> int:
        """统计以指定前缀开头的单词数量"""
        node = self.root
        for ch in prefix:
            if ch not in node.children:
                return 0
            node = node.children[ch]
        return node.count

# 应用：统计词频前缀匹配
trie = TrieWithCount()
words = ["apple", "app", "application", "apply", "apricot"]
for w in words:
    trie.insert(w)

print(trie.count_prefix("app"))   # 4: apple, app, application, apply
print(trie.count_prefix("apri"))  # 1: apricot
print(trie.count_prefix("z"))     # 0
